[ExtensionOf(classStr(CustAgingReportDP))]
final class ETG_CustAgingReportDP_Extension
{
    public boolean              financialDimensions;
    public DimensionSetName     financialDimSet;

}

Method.Source:
public void processReport()
{

    contract = this.parmDataContract() as CustAgingReportContract;

    financialDimensions             = contract.parmFinancialDimensions();
    financialDimSet                 = contract.parmFinancialDimSet();

    next processReport();

    if (contract.parmDetailed())
    {
        this.updateCustAgingReportTmp();
    }
}

public void updateCustAgingReportTmp()
{
    CustTrans                       custTrans;
    FinancialDimensionSetEntity     financialDimensionSetEntity;
    CustAgingReportTmp              custAgingReportTmp = this.getCustAgingReportTmp();

    ttsbegin;
    while select forupdate custAgingReportTmp
        where custAgingReportTmp.Voucher
        && custAgingReportTmp.TransDate
        && custAgingReportTmp.AccountNum
    {
        select firstonly DefaultDimension from custTrans
            where custTrans.AccountNum == custAgingReportTmp.AccountNum
            && custTrans.TransDate == custAgingReportTmp.TransDate
            && custTrans.Voucher == custAgingReportTmp.Voucher;

        custAgingReportTmp.DefaultDimension = custTrans.DefaultDimension;
        if (financialDimSet)
        {
            select firstonly financialDimensionSetEntity
            where financialDimensionSetEntity.Name == financialDimSet;

            if (financialDimensionSetEntity.SegmentName01)
            {
                custAgingReportTmp.SegmentValue01   = this.getFinDimValue(custTrans.DefaultDimension, financialDimensionSetEntity.SegmentName01);
                custAgingReportTmp.SegmentName01    = financialDimensionSetEntity.SegmentName01;
            }
            if (financialDimensionSetEntity.SegmentName02)
            {
                custAgingReportTmp.SegmentValue02   = this.getFinDimValue(custTrans.DefaultDimension, financialDimensionSetEntity.SegmentName02);
                custAgingReportTmp.SegmentName02    = financialDimensionSetEntity.SegmentName02;
            }
            if (financialDimensionSetEntity.SegmentName03)
            {
                custAgingReportTmp.SegmentValue03   = this.getFinDimValue(custTrans.DefaultDimension, financialDimensionSetEntity.SegmentName03);
                custAgingReportTmp.SegmentName03    = financialDimensionSetEntity.SegmentName03;
            }
            if (financialDimensionSetEntity.SegmentName04)
            {
                custAgingReportTmp.SegmentValue04   = this.getFinDimValue(custTrans.DefaultDimension, financialDimensionSetEntity.SegmentName04);
                custAgingReportTmp.SegmentName04    = financialDimensionSetEntity.SegmentName04;
            }
            if (financialDimensionSetEntity.SegmentName05)
            {
                custAgingReportTmp.SegmentValue05   = this.getFinDimValue(custTrans.DefaultDimension, financialDimensionSetEntity.SegmentName05);
                custAgingReportTmp.SegmentName05    = financialDimensionSetEntity.SegmentName05;
            }
            if (financialDimensionSetEntity.SegmentName06)
            {
                custAgingReportTmp.SegmentValue06   = this.getFinDimValue(custTrans.DefaultDimension, financialDimensionSetEntity.SegmentName06);
                custAgingReportTmp.SegmentName06    = financialDimensionSetEntity.SegmentName06;
            }
            if (financialDimensionSetEntity.SegmentName07)
            {
                custAgingReportTmp.SegmentValue07   = this.getFinDimValue(custTrans.DefaultDimension, financialDimensionSetEntity.SegmentName07);
                custAgingReportTmp.SegmentName07    = financialDimensionSetEntity.SegmentName07;
            }
            if (financialDimensionSetEntity.SegmentName08)
            {
                custAgingReportTmp.SegmentValue08   = this.getFinDimValue(custTrans.DefaultDimension, financialDimensionSetEntity.SegmentName08);
                custAgingReportTmp.SegmentName08    = financialDimensionSetEntity.SegmentName08;
            }
            if (financialDimensionSetEntity.SegmentName09)
            {
                custAgingReportTmp.SegmentValue09   = this.getFinDimValue(custTrans.DefaultDimension, financialDimensionSetEntity.SegmentName09);
                custAgingReportTmp.SegmentName09    = financialDimensionSetEntity.SegmentName09;
            }
            if (financialDimensionSetEntity.SegmentName10)
            {
                custAgingReportTmp.SegmentValue10   = this.getFinDimValue(custTrans.DefaultDimension, financialDimensionSetEntity.SegmentName10);
                custAgingReportTmp.SegmentName10    = financialDimensionSetEntity.SegmentName10;
            }
            if (financialDimensionSetEntity.SegmentName11)
            {
                custAgingReportTmp.SegmentValue11   = this.getFinDimValue(custTrans.DefaultDimension, financialDimensionSetEntity.SegmentName11);
                custAgingReportTmp.SegmentName11    = financialDimensionSetEntity.SegmentName11;
            }
        }
        custAgingReportTmp.update();
    }
    ttscommit;
}

public Description getFinDimValue(DimensionDefault _defaultDimension, Name     _dimensionName)
{
    DimensionAttributeValueSetStorage   dimStorage;
    DimensionAttribute                  dimAttribute;
    DimensionValue                      displayValue = "";
    Description                         dimDescription = "";
    int                                 i;

    dimStorage = DimensionAttributeValueSetStorage::find(_defaultDimension);
    for (i= 1 ; i<= dimStorage.elements() ; i++)
    {
        dimAttribute    = DimensionAttribute::find(dimStorage.getAttributeByIndex(i));

        if(dimAttribute.Name == _dimensionName)
        {
            displayValue    = dimStorage.getDisplayValueByIndex(i);
            dimDescription  = DimensionFinancialTag::findByFinancialTagCategoryAndValue(dimAttribute.financialTagCategory(), displayValue).Description;
            if (dimDescription == "")
            {
                dimDescription  = this.getFinDimValueDescription(dimAttribute.ViewName, displayValue);
            }
        }
    }

    return  dimDescription;
}

public Description getFinDimValueDescription(TableNameShort     _ViewName, DimensionValue   _displayValue)
{
    DimAttributeInventTable         inventTable;
    DimAttributeHcmWorker           worker;
    DimAttributeCustTable           custTable;
    DimAttributeVendTable           dimVendTable;
    DimAttributeAssetTable          assetTable;
    DimAttributeOMBusinessUnit      businessUnit;
    DimAttributeOMCostCenter        costCenter;
    DimAttributeOMDepartment        department;
    Description                     dimDescription = "";

    switch (_ViewName)
    {
        case  "DimAttributeInventTable":
            select Name from inventTable
                where inventTable.value == _displayValue;
            dimDescription = inventTable.Name;
            break;
        case  "DimAttributeHcmWorker":
            select Name from worker
                where worker.value == _displayValue;
            dimDescription = worker.Name;
            break;
        case  "DimAttributeCustTable":
            select Name from custTable
                where custTable.value == _displayValue;
            dimDescription = custTable.Name;
            break;
        case  "DimAttributeVendTable":
            select Name from dimVendTable
                where dimVendTable.value == _displayValue;
            dimDescription = dimVendTable.Name;
            break;
        case  "DimAttributeAssetTable":
            select Name from assetTable
                where assetTable.value == _displayValue;
            dimDescription = assetTable.Name;
            break;
        case  "DimAttributeOMBusinessUnit":
            select Name from businessUnit
                where businessUnit.value == _displayValue;
            dimDescription = businessUnit.Name;
            break;
        case  "DimAttributeOMCostCenter":
            select Name from costCenter
                where costCenter.value == _displayValue;
            dimDescription = costCenter.Name;
            break;
        case  "DimAttributeOMDepartment":
            select Name from department
                where department.value == _displayValue;
            dimDescription = department.Name;
            break;
    }

    return      dimDescription;
}
